// Забираем данные из указанных нод
const locations = $items('locations').map(i => i.json);
const rooms     = $items('rooms').map(i => i.json);
const assets    = $items('assets').map(i => i.json);

// Группируем активы по room_id
const assetsByRoom = {};
for (const a of assets) {
  (assetsByRoom[a.room_id] ||= []).push(a);
}

// Обогащаем комнаты списком активов
const roomsWithAssets = rooms.map(r => ({
  ...r,
  assets: assetsByRoom[r.id] || []
}));

// Группируем комнаты по location_id
const roomsByLocation = {};
for (const r of roomsWithAssets) {
  (roomsByLocation[r.location_id] ||= []).push(r);
}

// Возвращаем по одному item на локацию, с вложенными rooms[] и assets[]
return locations.map(loc => ({
  json: {
    ...loc,
    rooms: roomsByLocation[loc.id] || []
  }
}));

