(() => {
  const data = $items().map(i => i.json); // все входящие items -> массив локаций

  return `<!doctype html>
<html lang="ru">
<head>
<meta charset="utf-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>Активы по комнатам</title>
<style>
  :root{--bg:#0b0c0f;--card:#12141a;--muted:#8b95a7;--accent:#4f8cff;--chip:#232733}
  *{box-sizing:border-box}
  body{margin:0;background:#0b0c0f;color:#e5e7eb;font:14px/1.4 system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,Noto Sans,sans-serif}
  header{padding:20px 24px 0}
  h1{margin:0 0 12px;font-size:20px}
  .sub{color:#8b95a7;font-size:12px}
  main{padding:16px 24px}
  .table-card{background:var(--card);border:1px solid #1f2430;border-radius:14px;overflow:hidden}
  table{width:100%;border-collapse:collapse}
  thead th{background:#171a21;border-bottom:1px solid #232733;padding:10px 12px;text-align:left;font-weight:600;user-select:none}
  thead th.sortable{cursor:pointer}
  thead th .sort{opacity:.6;font-size:11px;margin-left:6px}
  tbody td{border-top:1px solid #141821;padding:10px 12px;vertical-align:top}
  tbody tr:hover{background:#121722}
  .muted{color:#8b95a7}
  .link{color:#9ec1ff;cursor:pointer}
  .badge{display:inline-flex;gap:6px;align-items:center;padding:3px 8px;border:1px solid #2a3342;border-radius:999px;background:var(--chip);font-size:12px}
  dialog{border:1px solid #2a3342;border-radius:12px;background:#0e1218;color:#e5e7eb;width:min(1100px,96vw)}
  dialog::backdrop{background:rgba(0,0,0,.5)}
  .modal-head{display:flex;justify-content:space-between;align-items:center;padding:10px 14px;border-bottom:1px solid #232733}
  .modal-body{padding:14px}
  .close{background:#1f2430;color:#cbd5e1;border:none;border-radius:8px;padding:6px 10px;cursor:pointer}
  .grid{display:grid;gap:8px}
</style>
</head>
<body>
<header>
  <h1>Активы по комнатам</h1>
  <div class="sub">Данные сформированы на сервере: локации → комнаты → активы.</div>
</header>

<main>
  <div class="table-card">
    <table id="tbl">
      <thead>
        <tr>
          <th class="sortable" data-key="location_name">Локация <span class="sort"></span></th>
          <th class="sortable" data-key="room_id">ID комнаты <span class="sort"></span></th>
          <th class="sortable" data-key="room_name">Комната <span class="sort"></span></th>
          <th class="sortable" data-key="floor">Этаж <span class="sort"></span></th>
          <th class="sortable" data-key="assets_cnt">Кол-во активов <span class="sort"></span></th>
          <th class="sortable" data-key="qty_sum">Сумма количества <span class="sort"></span></th>
          <th class="sortable" data-key="price_sum">Сумма цены <span class="sort"></span></th>
          <th></th>
        </tr>
      </thead>
      <tbody id="tbody"><tr><td colspan="8" class="muted">Отрисовка…</td></tr></tbody>
    </table>
  </div>
</main>

<dialog id="modal">
  <div class="modal-head">
    <div class="grid">
      <div><strong>Комната: <span id="m-room-name"></span></strong></div>
      <div class="sub">Локация: <span id="m-loc-name"></span> • Этаж: <span id="m-floor"></span> • Активов: <span id="m-cnt"></span></div>
    </div>
    <button class="close" onclick="modal.close()">Закрыть</button>
  </div>
  <div class="modal-body">
    <div class="table-card" style="background:#0f1218">
      <table>
        <thead>
          <tr>
            <th>#</th><th>ID</th><th>Код</th><th>Наименование</th><th>Кол-во</th><th>Цена</th><th>Комментарий</th>
          </tr>
        </thead>
        <tbody id="m-assets"></tbody>
      </table>
    </div>
  </div>
</dialog>

<script>window.SERVER_DATA = ${JSON.stringify(data)};</script>

<script>
const $ = (s)=>document.querySelector(s);
const tbody = $('#tbody');
const modal = $('#modal');

let sortKey = 'location_name';
let sortDir = 'asc';

// Собираем плоский список «комнат» из локаций
function flattenRooms(locations){
  const rows = [];
  for (const loc of (locations||[])) {
    const rooms = Array.isArray(loc.rooms) ? loc.rooms : [];
    for (const r of rooms) {
      const assets = Array.isArray(r.assets) ? r.assets : [];
      const qtySum = assets.reduce((s,a)=> s + (Number(a.quantity)||0), 0);
      const priceSum = assets.reduce((s,a)=> s + (parseFloat(String(a.price||'0').replace(',', '.'))||0), 0);
      rows.push({
        location_id: loc.id,
        location_name: loc.name || '',
        room_id: r.id,
        room_name: r.name || '',
        floor: r.floor ?? '',
        assets_cnt: assets.length,
        qty_sum: qtySum,
        price_sum: priceSum,
        _assets: assets
      });
    }
  }
  return rows;
}

function fmtMoney(n){
  if (!isFinite(n)) return '';
  return new Intl.NumberFormat('ru-RU', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(n);
}

function compare(a,b){
  const dir = sortDir==='asc' ? 1 : -1;
  const v1 = a[sortKey], v2 = b[sortKey];
  if (typeof v1 === 'string' && typeof v2 === 'string') return v1.localeCompare(v2,'ru') * dir;
  return ((v1??0) - (v2??0)) * dir;
}

function setSortIndicators(){
  document.querySelectorAll('thead th.sortable').forEach(th=>{
    const span = th.querySelector('.sort');
    if(!span) return;
    const key = th.dataset.key;
    span.textContent = (key===sortKey) ? (sortDir==='asc'?'▲':'▼') : '';
  });
}

function renderList(locations){
  const rooms = flattenRooms(locations);
  if (!rooms.length) {
    tbody.innerHTML = '<tr><td colspan="8" class="muted">Нет данных</td></tr>';
    return;
  }
  rooms.sort(compare);
  tbody.innerHTML = rooms.map(r => (
    '<tr>'
      + '<td>' + r.location_name + '</td>'
      + '<td>#' + r.room_id + '</td>'
      + '<td>' + r.room_name + '</td>'
      + '<td>' + r.floor + '</td>'
      + '<td><span class="badge">' + r.assets_cnt + '</span></td>'
      + '<td>' + r.qty_sum + '</td>'
      + '<td>' + fmtMoney(r.price_sum) + '</td>'
      + '<td><span class="link" data-room-id="' + r.room_id + '">Открыть</span></td>'
    + '</tr>'
  )).join('');

  // обработчики открытия модалки
  tbody.querySelectorAll('.link').forEach(a=>{
    a.addEventListener('click', ()=>{
      const roomId = Number(a.dataset.roomId);
      const row = rooms.find(x=> x.room_id === roomId);
      if (!row) return;
      openDetail(row);
    });
  });

  setSortIndicators();
}

function openDetail(row){
  $('#m-room-name').textContent = '#' + row.room_id + ' — ' + row.room_name;
  $('#m-loc-name').textContent  = row.location_name;
  $('#m-floor').textContent     = String(row.floor || '');
  $('#m-cnt').textContent       = String(row.assets_cnt);

  const assets = (row._assets||[]).slice().sort((a,b)=> (a.id||0)-(b.id||0));
  const html = assets.map((a, i)=>(
    '<tr>'
      + '<td>' + (i+1) + '</td>'
      + '<td>' + a.id + '</td>'
      + '<td>' + (a.asset_code || '') + '</td>'
      + '<td>' + (a.name || '') + '</td>'
      + '<td>' + (a.quantity ?? '') + '</td>'
      + '<td>' + fmtMoney(parseFloat(String(a.price||'0').replace(",", "."))||0) + '</td>'
      + '<td>' + (a.comments ?? '') + '</td>'
    + '</tr>'
  )).join('');
  $('#m-assets').innerHTML = html || '<tr><td colspan="7" class="muted">Нет активов</td></tr>';

  modal.showModal();
}

// сортировка по клику в шапке
document.addEventListener('DOMContentLoaded', ()=>{
  document.querySelectorAll('thead th.sortable').forEach(th=>{
    th.addEventListener('click', ()=>{
      const key = th.dataset.key;
      if (!key) return;
      if (sortKey === key) sortDir = (sortDir==='asc') ? 'desc' : 'asc';
      else { sortKey = key; sortDir = 'asc'; }
      renderList(window.SERVER_DATA);
    });
  });

  renderList(window.SERVER_DATA);
});
</script>
</body>
</html>`;
})()
}}
